def inv(len, minDiff):
  return And(len >= 0, minDiff >= 0)

def addStockOrder(len, len1, stock, order, minDiff, minDiff1):
  precondition = And(stock >= 0, order >= 0, order <= stock)

  len_update = (len1 == len + 1)
  min_diff_update = If(stock - order < minDiff, stock - order, minDiff)
  min_diff_transition = (minDiff1 == min_diff_update)

  postcondition = And(len_update, min_diff_transition)

  return Implies(precondition, postcondition)
